class Solution(object):
    def maxNumOfMarkedIndices(self, nums):
        nums.sort()
        n = len(nums)

        def feasible(k):
            # Match nums[0..k-1] with nums[n-k..n-1]
            for i in range(k):
                if 2 * nums[i] > nums[n - k + i]:
                    return False
            return True

        lo, hi = 0, n // 2
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo * 2
